    16→export default function EditSalonPage() {
    17→  const { user } = useAuth();
    18→  const navigate = useNavigate();
    19→  const { id } = useParams<{ id: string }>();
    20→
    21→  const [isLoading, setIsLoading] = useState(true);
    22→  const [isSaving, setIsSaving] = useState(false);
    23→  const [formData, setFormData] = useState<SalonFormData>({
    24→    nomeFantasia: "",
    25→    razaoSocial: "",
    26→    cnpj: "",
    27→    telefoneComercial: "",
    28→    emailContato: "",
    29→    nomeLinkUtil: "",
    30→    urlLinkUtil: "",
    31→    timezone: "America/Sao_Paulo",
    32→  });
    33→  const [active, setActive] = useState(true);
    34→
    35→  const loadSalon = useCallback(async (): Promise<void> => {
    36→    if (!id) {
    37→      toast.error("ID do salão não encontrado");
    38→      navigate("/admin/salons");
    39→      return;
    40→    }
    41→
    42→    try {
    43→      setIsLoading(true);
    44→      const salon = await salonService.getById(id);
    45→      setFormData({
    46→        nomeFantasia: salon.name ?? "",
    47→        razaoSocial: salon.responsible ?? "",
    48→        cnpj: salon.cnpj ?? "",
    49→        telefoneComercial: salon.phone ?? "",
    50→        emailContato: salon.email ?? "",
    51→        nomeLinkUtil: salon.websiteName ?? "",
    52→        urlLinkUtil: salon.websiteUrl ?? "",
    53→        timezone: salon.timezone ?? "America/Sao_Paulo",
    54→      });
    55→      setActive(salon.active ?? true);
    56→    } catch {
    57→      toast.error("Erro ao carregar dados do salão");
    58→      navigate("/admin/salons");
    59→    } finally {
    60→      setIsLoading(false);
    61→    }
    62→  }, [id, navigate]);
    63→
    64→  useEffect(() => {
    65→    void loadSalon();
    66→  }, [loadSalon]);
    67→
    68→  const validate = (): boolean => {
    69→    if (!formData.nomeFantasia.trim()) {
    70→      toast.error("Por favor, preencha o nome fantasia");
    71→      return false;
    72→    }
    73→    if (!formData.telefoneComercial.trim()) {
    74→      toast.error("Por favor, preencha o telefone");
    75→      return false;
    76→    }
