    78→      toast.error("CNPJ inválido");
    79→      return false;
    80→    }
    81→    return true;
    82→  };
    83→
    84→  const handleSave = async (): Promise<void> => {
    85→    if (!validate() || !id) return;
    86→
    87→    setIsSaving(true);
    88→
    89→    try {
    90→      const updateData: UpdateSalonDto = {
    91→        name: formData.nomeFantasia.trim(),
    92→        responsible: formData.razaoSocial.trim() || undefined,
