    94→        phone: salonService.formatPhone(formData.telefoneComercial),
    95→        email: formData.emailContato.trim() || undefined,
    96→        timezone: formData.timezone,
    97→        websiteName: formData.nomeLinkUtil.trim() || undefined,
    98→        websiteUrl: formData.urlLinkUtil.trim() || undefined,
    99→        active,
   100→      };
   101→
   102→      await salonService.update(id, updateData);
   103→      toast.success("Salão atualizado com sucesso!");
   104→      navigate("/admin/salons");
   105→    } catch (error: unknown) {
   106→      const errorMessage =
   107→        (error as { response?: { data?: { message?: string } } })?.response?.data?.message ||
   108→        "Erro ao salvar as alterações do salão";
   109→      toast.error(errorMessage);
   110→    } finally {
   111→      setIsSaving(false);
   112→    }
   113→  };
   114→
   115→  if (isLoading) {
   116→    return (
   117→      <EasySalonLayout
   118→        sideNavItems={getAdminNavItems(user?.role || "Easy Salon")}
   119→        sideNavTitle="Easy Salon"
   120→        sideNavSubtitle="Área Administrativa"
   121→      >
   122→        <div className="flex items-center justify-center h-64">
   123→          <LoadingSpinner size="md" />
   124→        </div>
   125→      </EasySalonLayout>
   126→    );
   127→  }
   128→
   129→  return (
   130→    <EasySalonLayout
   131→      sideNavItems={getAdminNavItems(user?.role || "Easy Salon")}
   132→      sideNavTitle="Easy Salon"
   133→      sideNavSubtitle="Área Administrativa"
   134→    >
   135→      <div className="flex items-center gap-4 mb-6">
   136→        <Button variant="secondary" size="icon" onClick={() => navigate("/admin/salons")}>
   137→          <ArrowLeft className="h-5 w-5" />
   138→        </Button>
   139→        <div>
   140→          <h1 className="page-title">Editar Salão</h1>
   141→          <p className="text-[13px] text-muted-foreground">Atualize as informações do salão</p>
   142→        </div>
   143→      </div>
   144→
   145→      <div className="bg-card border border-border rounded-lg">
   146→        <div className="p-6">
   147→          <SalonForm
   148→            data={formData}
   149→            onChange={setFormData}
   150→            disabled={isSaving}
   151→          />
   152→
   153→          <div className="flex items-center justify-between mt-8 pt-6 border-t">
   154→            <div className="flex items-center gap-2">
   155→              <Switch
   156→                id="edit-salon-active"
   157→                checked={active}
   158→                onCheckedChange={setActive}
   159→                disabled={isSaving}
   160→              />
   161→              <Label htmlFor="edit-salon-active" className="cursor-pointer select-none">
   162→                {active ? "Ativo" : "Inativo"}
   163→              </Label>
   164→            </div>
   165→
   166→            <Button
   167→              onClick={() => { void handleSave(); }}
   168→              disabled={isSaving}
   169→              className="px-8"
   170→            >
   171→              {isSaving ? (
   172→                <>
   173→                  <LoadingSpinner size="sm" inline className="mr-2" />
   174→                  Salvando...
   175→                </>
   176→              ) : (
   177→                "Salvar alterações"
   178→              )}
   179→            </Button>
   180→          </div>
   181→        </div>
   182→      </div>
   183→    </EasySalonLayout>
   184→  );
   185→}
